var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤. 주변에 반응은?","JPN":"サシャ、周りに反応は？","ENG":"Sasha, are there any signals around us?","TWN":"莎夏。周圍還有反應嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"없어. 상황종료야!","JPN":"ない。オールオッケーだよ！","ENG":"Nope! It's all clear!","TWN":"沒有。已經結束了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"믿을 수가 없네. 맨손으로 침식체들을 박살 내다니…!","JPN":"信じられない。侵食体を素手でぶちのめした……！","ENG":"Unbelievable. She defeated those C.O.s with her bare hands...!","TWN":"不敢相信，居然能徒手擊敗侵蝕體……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"뭐 하는 녀석이지? 그 몸은 대체 뭐고?","JPN":"いったい何者？　その体はどうなってるの？","ENG":"Who is she? And what's up with her body?","TWN":"她是什麼人？那副身體到底是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그만하세요 올가 언니! 얘는 제 친구예요!","JPN":"ちょっと、止めてくださいオルガさん！　この子は私の友だちです！","ENG":"Stop it, Olga! She's my friend!","TWN":"住手，歐嘉姊姊！她是我的朋友！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"친구라고?","JPN":"友だち？","ENG":"Your friend?","TWN":"朋友？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"으엑… 너도 친구가 있었어? 라는 말투…","JPN":"そんな……あなた、友だちいたの？って言い方……","ENG":"Egh... that I-can't-believe-you-have-friends tone...","TWN":"呃……怎麼一副懷疑的語氣……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"어이 사샤, 매번 뭔갈 만들더니, 진짜 대단한 걸 가져왔네?","JPN":"おい、サシャ。しょっちゅう何か作ってると思ったら、今回は本当にすごいものを持ってきたじゃないか！","ENG":"Hey, Sasha. You always were making something, and it seems like you brought something truly amazing this time.","TWN":"喂，莎夏，你每天自己在那邊弄東弄西的，結果還真的弄出個這麼厲害的東西啊？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L18_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"저번엔 그리 대단한 건 못 만든다면서, 우릴 속인 거야?","JPN":"この前は大したもの作れないって言っておいて、あれは嘘だったのか？","ENG":"Did you fool us by saying that you couldn't make anything good last time?","TWN":"對啊！上次還說沒辦法，不會是在騙我們吧？哈哈！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다들 물러서.","JPN":"全員、下がって。","ENG":"Everyone, step back.","TWN":"都給我退後。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"으음?!","JPN":"えっ！？","ENG":"Mmm?!","TWN":"唔？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"괜찮아 마브카. 이분들은 모두 내 동료들이야.","JPN":"大丈夫だよ、マブカ。この人たちは皆私の仲間だから。","ENG":"It's okay, Mavka. These people are all my friends.","TWN":"沒關係，瑪卡。這些人都是我的同伴。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"전투를 치루고 나면 흥분이 가시지 않아서 말이야. 소개가 늦었군.","JPN":"戦闘後は昂ぶりがなかなか収まらなくてな。自己紹介が遅れてしまったな。","ENG":"It takes me a while to calm down after a battle. Guess I forgot to introduce myself.","TWN":"喔……戰鬥結束後情緒還沒平復過來。忘了介紹了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"우린 시린그라드의 민병단이다. 저쪽은 안드레이 형님, 그리고 이쪽은 올가 누님이지.","JPN":"俺たちはシリングラードの民兵団だ。あっちはアンドレイの兄貴、こっちはオルガの姉貴だ。","ENG":"We are Ciringrad's militia. That's Andrei over there, and this is Olga.","TWN":"我們是錫林格勒的民兵團。那位是安德烈，安哥，這位是歐嘉，歐姊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"넌 이름이 뭐냐.","JPN":"お前は？","ENG":"What's your name?","TWN":"你叫什麼名字。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……마브카.","JPN":"……マブカ。","ENG":"...Mavka.","TWN":"……瑪卡。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"동화에서나 듣던 이름 같은데?","JPN":"おとぎ話とかで聞いた名前だな。","ENG":"Sounds like a name from a fairytale.","TWN":"聽起來像是童話裡的名字？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"어쨌든 대단한 힘이구만! 우리도 그런 팔 하나쯤 있었으면 좋았을 텐데.","JPN":"まあとにかく、大した実力だったぞ！　俺もそんな腕一本ぐらいあればな。","ENG":"Anyway, that was some feat! I wish I had an arm like that.","TWN":"不管怎樣，真是了不起！要是我們也有一隻這樣的手臂就好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아니, 본래의 절반도 내지 못했어.","JPN":"いや、本来の力の半分も出せなかった。","ENG":"No, that wasn't even half of my powers.","TWN":"不，我還沒發揮出原本力量的一半。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그러고보니 너 포스터에서 본 녀석들과 비슷한 것 같은데…","JPN":"そういえばあなた……ポスターで見たやつらと似てる気がするんだけど……","ENG":"Come to think of it, you look like one of the girls from the poster...","TWN":"說起來，你好像和海報上的那些傢伙很像……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"설마 북방군이야? 여긴 무슨 일로 왔지?","JPN":"まさか北方軍？　ここには何をしに来たの？","ENG":"Are you from the Northern Army? What brings you here?","TWN":"難道是北方軍的人？你來這裡幹什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"오해에요 언니. 마브카는 침식지대에 있던 절 구해줬다구요!","JPN":"オルガさん、誤解です！　マブカは侵食地帯で私を助けてくれたんですよ！","ENG":"That's a misunderstanding, Olga. Mavka saved me when I was in the Corrupted Area!","TWN":"誤會了，姊姊。瑪卡在侵蝕區救了我！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"앗……!","JPN":"あっ……！","ENG":"Oops...!","TWN":"糟糕……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"사샤 너. 침식지대에 혼자 가지 말라고 그렇게 말했는데…!","JPN":"サシャ、一人で侵食地帯に行っちゃだめだとあれほど言ったのに……！","ENG":"Sasha, didn't I tell you to not go in the Corrupted Area alone...?!","TWN":"莎夏，我不是說過不要一個人去侵蝕區嗎……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"어, 어쨌든 마브카는 절 구해준 은인이니까 괜찮다구요!","JPN":"と、とにかく、マブカは私の命の恩人だから大丈夫なんです！","ENG":"A-anyway, Mavka saved my life, so she's okay!","TWN":"總，總之，瑪卡是我的救命恩人，所以沒關係！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너무 그러지 않아도 돼. 의심하는 게 당연하잖아.","JPN":"いいの。疑われてもしかたないもの。","ENG":"You don't have to keep defending me. It's natural to be suspicious.","TWN":"不用幫我說話，懷疑是正常的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"숨길 생각은 없어. 난 북방군 출신이 맞아.","JPN":"隠すつもりはない。私は確かに北方軍の出身だ。","ENG":"I don't intend on hiding it. Yes, I am from the Northern Army.","TWN":"我無意隱瞞，我確實是北方軍出身。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"뭐, 뭣?!","JPN":"な、何！？","ENG":"W-what?!","TWN":"什，什麼？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"하지만 결국 폐기되었어.","JPN":"でも、結局破棄された。","ENG":"But I was discarded.","TWN":"但我被他們廢棄了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"분명 난 죽었다고 생각했는데, 사샤가 날 구해줬지.","JPN":"自分でも死んだと思っていたところを、サシャに助けられたんだ。","ENG":"I thought I was dead. But then, Sasha saved me.","TWN":"我明明以為自己已經死了，但莎夏救了我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"도움을 받았으니까 보답으로 곁에 있어줄 뿐이야.","JPN":"助けてもらったから、お礼をするために私もそばにいるだけ。","ENG":"All I wanted to do was repay the favor by her side.","TWN":"因為得到了幫助，所以只是作為報答留在她身邊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"唔……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"모두 살아남았나? 다행이군.","JPN":"皆無事でよかったな。","ENG":"Is everyone alive? Thank goodness.","TWN":"大家都活下來了嗎？太好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"미안하지만 안 좋은 소식이다. 이걸 봐.","JPN":"だが悪い知らせがある。これを見ろ。","ENG":"Sorry, but I have some bad news. Look at this.","TWN":"抱歉，有個壞消息。看這個。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이터니움이 검은색이잖아? 양도 좀 적은 것 같은데.","JPN":"エタニウムの色が黒い……？　量も少ない気がする。","ENG":"Why is this Eternium black? And the amount seems a bit small.","TWN":"永恆之金怎麼是黑色的？數量好像也少了點。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"맞아. 오염된 것 같아. 목숨을 걸고 싸웠는데 허탕이나 다름없군.","JPN":"ああ、どうやら汚染されたようだ。命をかけて戦ったのに残念だな。","ENG":"You're right. It's contaminated. We risked our lives for nothing.","TWN":"沒錯。好像被污染了。冒著危險戰鬥卻等於白費力氣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"뭐… 마을에 피해가 없는 것만으로도 다행이라 여겨야겠지.","JPN":"まあ……村に被害がなかっただけよしとするか。","ENG":"Well... we should be thankful that there wasn't any damage to the village.","TWN":"不過……至少沒有波及村子，也算是不幸中的大幸吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그리고….","JPN":"あと……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"멀리서 들었다. 마브카라고 했나?","JPN":"さっきの話は遠くから聞いていた。マブカと言ったか。","ENG":"I heard from afar. Your name is Mavka, right?","TWN":"我來的時候聽到，你是叫瑪卡嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마을을 위해 싸워준 건 고맙다. 하지만 우린 널 좋게 생각할 수 없어.","JPN":"村のために戦ってくれたことには感謝する。だが俺たちはお前に好意を抱くことはできない。","ENG":"Thank you for protecting the village. But we can't think well of you.","TWN":"能夠為村子而戰很感激，但我們無法對你抱有好感。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"지금은 사샤를 봐서 넘어가겠지만 우린 널 주시하고 있다는 걸 알아둬라.","JPN":"今はサシャに免じて好きにさせてやるが、常に注視しているということは忘れるな。","ENG":"We'll let it slide this time because of Sasha, but just know that we'll be keeping a close eye on you.","TWN":"看在莎夏的面子上，這次就算了，但你要知道我們會盯著你。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……알고 있어.","JPN":"……わかってる。","ENG":"...I know.","TWN":"……我知道。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"오늘은 이만 철수다!","JPN":"今日はもう上がりだ！","ENG":"Okay! Let's all head back home!","TWN":"今天就到此為止。回去吧，大家！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"다행이다 마브카.","JPN":"よかったね、マブカ。","ENG":"I'm so relieved, Mavka.","TWN":"呼……還好還好，瑪卡。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"저분들은 민병단이라 경계하는 것 뿐이야. 내가 옆에 있어줄 테니까 걱정하지마.","JPN":"あの人たちは民兵団だから警戒を怠れないだけだよ。私が一緒にいるから安心して。","ENG":"They are just cautious because they're the militia. You won't have to worry because I'll be beside you.","TWN":"因為他們是民兵團，才這麼警戒。別擔心，我會在你身邊的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"괜찮다니까 그러네.","JPN":"だから大丈夫だって。","ENG":"I told you, I'm fine.","TWN":"……我沒關係。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};